import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Validate user input length to prevent buffer overflow
        if (userInput.length() > 10) {
            System.out.println("Input exceeds buffer size limit. Please enter a shorter string.");
            return;
        }

        // Use a char array instead of byte array to avoid potential encoding issues
        char[] buffer = new char[10];
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Buffer overflow prevented!");
    }
}

### Explanation:
